import{_ as r,o as l,c as e,a2 as o}from"./chunks/framework.BRk9mohw.js";const p=JSON.parse('{"title":"隐私政策","description":"","frontmatter":{},"headers":[],"relativePath":"privacy.md","filePath":"privacy.md"}'),t={name:"privacy.md"};function i(n,a,s,h,d,c){return l(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="隐私政策" tabindex="-1">隐私政策 <a class="header-anchor" href="#隐私政策" aria-label="Permalink to &quot;隐私政策&quot;">​</a></h1><p><strong>最后更新</strong>: 2026-03-21</p><hr><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>欢迎来到 OpenClaw 中文网（以下简称&quot;本网站&quot;）。我们重视您的隐私权，并致力于保护您的个人信息安全。本隐私政策说明我们如何收集、使用和保护您的信息。</p><hr><h2 id="我们收集的信息" tabindex="-1">我们收集的信息 <a class="header-anchor" href="#我们收集的信息" aria-label="Permalink to &quot;我们收集的信息&quot;">​</a></h2><h3 id="_1-自动收集的信息" tabindex="-1">1. 自动收集的信息 <a class="header-anchor" href="#_1-自动收集的信息" aria-label="Permalink to &quot;1. 自动收集的信息&quot;">​</a></h3><p>当您访问本网站时，我们可能会自动收集以下信息：</p><ul><li><strong>设备信息</strong>: 浏览器类型、操作系统、设备型号</li><li><strong>使用数据</strong>: 访问页面、停留时间、点击行为</li><li><strong>技术数据</strong>: IP 地址、访问日期和时间、引荐来源</li></ul><h3 id="_2-cookie-和类似技术" tabindex="-1">2. Cookie 和类似技术 <a class="header-anchor" href="#_2-cookie-和类似技术" aria-label="Permalink to &quot;2. Cookie 和类似技术&quot;">​</a></h3><p>本网站使用 Cookie 来：</p><ul><li>改善用户体验</li><li>分析网站流量</li><li>提供个性化内容</li></ul><p>您可以通过浏览器设置管理或禁用 Cookie。</p><hr><h2 id="我们如何使用信息" tabindex="-1">我们如何使用信息 <a class="header-anchor" href="#我们如何使用信息" aria-label="Permalink to &quot;我们如何使用信息&quot;">​</a></h2><p>我们可能将收集的信息用于以下目的：</p><ul><li><strong>提供服务</strong>: 维护和改进网站功能</li><li><strong>数据分析</strong>: 了解用户行为，优化内容</li><li><strong>安全防护</strong>: 检测和防止欺诈行为</li><li><strong>法律合规</strong>: 履行法律义务</li></ul><hr><h2 id="信息共享和披露" tabindex="-1">信息共享和披露 <a class="header-anchor" href="#信息共享和披露" aria-label="Permalink to &quot;信息共享和披露&quot;">​</a></h2><h3 id="我们不会" tabindex="-1">我们不会： <a class="header-anchor" href="#我们不会" aria-label="Permalink to &quot;我们不会：&quot;">​</a></h3><ul><li>出售您的个人信息</li><li>将个人信息出租给第三方</li></ul><h3 id="我们可能共享" tabindex="-1">我们可能共享： <a class="header-anchor" href="#我们可能共享" aria-label="Permalink to &quot;我们可能共享：&quot;">​</a></h3><ul><li><strong>服务提供商</strong>: 帮助我们运营网站的可信第三方（如托管服务、分析服务）</li><li><strong>法律要求</strong>: 应法律要求或保护权利的需要</li></ul><hr><h2 id="第三方服务" tabindex="-1">第三方服务 <a class="header-anchor" href="#第三方服务" aria-label="Permalink to &quot;第三方服务&quot;">​</a></h2><p>本网站可能包含第三方服务或链接，例如：</p><ul><li><strong>Google AdSense</strong>: 广告投放服务</li><li><strong>Google Analytics</strong>: 网站分析服务</li><li><strong>GitHub</strong>: 代码托管和 Issue 追踪</li><li><strong>Discord</strong>: 社区交流平台</li></ul><p>这些第三方服务有自己的隐私政策，我们建议您阅读它们的隐私条款。</p><hr><h2 id="数据安全" tabindex="-1">数据安全 <a class="header-anchor" href="#数据安全" aria-label="Permalink to &quot;数据安全&quot;">​</a></h2><p>我们采取合理的安全措施保护您的信息：</p><ul><li>使用 HTTPS 加密传输</li><li>定期更新系统和软件</li><li>限制数据访问权限</li></ul><p>但请注意，互联网传输并非绝对安全，我们无法保证 100% 的安全性。</p><hr><h2 id="您的权利" tabindex="-1">您的权利 <a class="header-anchor" href="#您的权利" aria-label="Permalink to &quot;您的权利&quot;">​</a></h2><p>根据适用法律，您可能享有以下权利：</p><ul><li><strong>访问权</strong>: 请求访问我们收集的您的个人信息</li><li><strong>更正权</strong>: 请求更正不准确的个人信息</li><li><strong>删除权</strong>: 请求删除您的个人信息</li><li><strong>退出权</strong>: 退出某些数据处理活动</li></ul><p>如需行使这些权利，请通过以下方式联系我们。</p><hr><h2 id="儿童隐私" tabindex="-1">儿童隐私 <a class="header-anchor" href="#儿童隐私" aria-label="Permalink to &quot;儿童隐私&quot;">​</a></h2><p>本网站不面向 13 岁以下儿童。我们不会故意收集 13 岁以下儿童的个人信息。</p><hr><h2 id="隐私政策变更" tabindex="-1">隐私政策变更 <a class="header-anchor" href="#隐私政策变更" aria-label="Permalink to &quot;隐私政策变更&quot;">​</a></h2><p>我们可能会不时更新本隐私政策。更新后的政策将发布在本页面，并注明&quot;最后更新&quot;日期。</p><p>建议您定期查看本政策以了解任何变化。</p><hr><h2 id="联系我们" tabindex="-1">联系我们 <a class="header-anchor" href="#联系我们" aria-label="Permalink to &quot;联系我们&quot;">​</a></h2><p>如果您对本隐私政策有任何疑问或意见，请通过以下方式联系我们：</p><ul><li><strong>GitHub</strong>: <a href="https://github.com/openclaw/openclaw/issues" target="_blank" rel="noreferrer">https://github.com/openclaw/openclaw/issues</a></li><li><strong>Discord</strong>: <a href="https://discord.gg/clawd" target="_blank" rel="noreferrer">https://discord.gg/clawd</a></li><li><strong>电子邮件</strong>: <a href="mailto:openclaw.adsense@gmail.com" target="_blank" rel="noreferrer">openclaw.adsense@gmail.com</a></li></ul><hr><h2 id="同意" tabindex="-1">同意 <a class="header-anchor" href="#同意" aria-label="Permalink to &quot;同意&quot;">​</a></h2><p>使用本网站即表示您同意本隐私政策。如果您不同意本政策的任何条款，请不要使用本网站。</p><hr><p><strong>生效日期</strong>: 2026-03-21</p>',55)])])}const g=r(t,[["render",i]]);export{p as __pageData,g as default};
